bool VehicleTracker::conditionedUpdate(
  const types::DynamicObject & measurement, const types::DynamicObject & prediction,
  const autoware_perception_msgs::msg::Shape & tracker_shape, const rclcpp::Time & measurement_time,
  const types::InputChannel & channel_info)
{
  // Determine update strategy
  UpdateStrategy strategy = determineUpdateStrategy(measurement, prediction);

  // Handle weak update strategy (no edge alignment - use weak update with pseudo measurement)
  if (strategy.type == UpdateStrategyType::WEAK_UPDATE) {
    // Use weak update strategy with pseudo measurement
    types::DynamicObject pseudo_measurement = prediction;

    // Create pseudo measurement with enlarged covariance for weak update
    createPseudoMeasurement(measurement, pseudo_measurement, tracker_shape, true);

    // Apply the weak measurement update using existing mechanism
    measure(pseudo_measurement, measurement_time, channel_info);

    return true;
  }

  // Handle wheel-based update strategies (FRONT_WHEEL_UPDATE or REAR_WHEEL_UPDATE)
  // Use motion model's pose covariance for anchor point uncertainty
  std::array<double, 36> pose_cov = measurement.pose_covariance;

  bool is_updated = false;
  if (strategy.type == UpdateStrategyType::FRONT_WHEEL_UPDATE) {
    shape_update_anchor_ = BicycleMotionModel::LengthUpdateAnchor::FRONT;

    is_updated = motion_model_.updateStatePoseFront(
      strategy.anchor_point.x, strategy.anchor_point.y, pose_cov);
  } else {
    // Must be REAR_WHEEL_UPDATE (only remaining option after WEAK_UPDATE check)
    shape_update_anchor_ = BicycleMotionModel::LengthUpdateAnchor::REAR;

    is_updated =
      motion_model_.updateStatePoseRear(strategy.anchor_point.x, strategy.anchor_point.y, pose_cov);
  }

  removeCache();

  return is_updated;
}

UpdateStrategy VehicleTracker::determineUpdateStrategy(
  const types::DynamicObject & measurement, const types::DynamicObject & prediction) const
{
  UpdateStrategy strategy;

  // 1. Calculate edge centers for measurement vehicle
  const EdgePositions meas_edges = calculateEdgeCenters(measurement);

  // 2. Calculate alignment distances between measurement and prediction edges
  const EdgeAlignment alignment = findAlignedEdges(meas_edges, prediction);

  // 3. Check if any edge is well-aligned (within threshold ratio of vehicle length)
  const double predicted_length = prediction.shape.dimensions.x;
  const bool is_edge_aligned =
    (alignment.min_alignment_distance / predicted_length) < ALIGNMENT_RATIO_THRESHOLD;

  // 4. If no edge is aligned, use weak update strategy
  if (!is_edge_aligned) {
    strategy.type = UpdateStrategyType::WEAK_UPDATE;
    return strategy;
  }

  // 5. Determine aligned edge and calculate anchor point
  strategy.type = (alignment.aligned_pred_edge == Edge::FRONT)
                    ? UpdateStrategyType::FRONT_WHEEL_UPDATE
                    : UpdateStrategyType::REAR_WHEEL_UPDATE;
  strategy.anchor_point = calculateAnchorPoint(alignment, measurement);

  return strategy;
}

VehicleTracker::EdgePositions VehicleTracker::calculateEdgeCenters(
  const types::DynamicObject & obj) const
{
  const double yaw = tf2::getYaw(obj.pose.orientation);
  const double cos_yaw = std::cos(yaw);
  const double sin_yaw = std::sin(yaw);
  const double half_length = obj.shape.dimensions.x * 0.5;

  return {
    obj.pose.position.x + half_length * cos_yaw,  // front_x
    obj.pose.position.y + half_length * sin_yaw,  // front_y
    obj.pose.position.x - half_length * cos_yaw,  // rear_x
    obj.pose.position.y - half_length * sin_yaw   // rear_y
  };
}

VehicleTracker::EdgeAlignment VehicleTracker::findAlignedEdges(
  const EdgePositions & meas_edges, const types::DynamicObject & prediction) const
{
  // Project edges onto predicted vehicle's longitudinal axis for comparison
  const double pred_yaw = tf2::getYaw(prediction.pose.orientation);
  const double pred_cos_yaw = std::cos(pred_yaw);
  const double pred_sin_yaw = std::sin(pred_yaw);

  const auto project_to_axis = [pred_cos_yaw, pred_sin_yaw](double x, double y) {
    return x * pred_cos_yaw + y * pred_sin_yaw;
  };

  // Project measurement edges onto predicted vehicle's axis
  const double meas_front_axis = project_to_axis(meas_edges.front_x, meas_edges.front_y);
  const double meas_rear_axis = project_to_axis(meas_edges.rear_x, meas_edges.rear_y);

  // Calculate predicted edges along its longitudinal axis
  const double pred_center_axis =
    prediction.pose.position.x * pred_cos_yaw + prediction.pose.position.y * pred_sin_yaw;
  const double predicted_half_length = prediction.shape.dimensions.x * 0.5;
  const double pred_front_axis = pred_center_axis + predicted_half_length;
  const double pred_rear_axis = pred_center_axis - predicted_half_length;

  // Define all four edge alignment candidates
  struct Candidate
  {
    double distance;
    Edge pred_edge;
    Edge meas_edge;
  };
  const std::array<Candidate, 4> candidates = {
    {{std::abs(meas_front_axis - pred_front_axis), Edge::FRONT, Edge::FRONT},
     {std::abs(meas_rear_axis - pred_front_axis), Edge::FRONT, Edge::REAR},
     {std::abs(meas_front_axis - pred_rear_axis), Edge::REAR, Edge::FRONT},
     {std::abs(meas_rear_axis - pred_rear_axis), Edge::REAR, Edge::REAR}}};

  // Find the best aligned edge pair
  const auto best = std::min_element(
    candidates.begin(), candidates.end(),
    [](const Candidate & a, const Candidate & b) { return a.distance < b.distance; });

  return {best->distance, best->pred_edge, best->meas_edge};
}

const auto project_to_axis = [pred_cos_yaw, pred_sin_yaw](double x, double y) {
  return x * pred_cos_yaw + y * pred_sin_yaw;
};

geometry_msgs::msg::Point VehicleTracker::calculateAnchorPoint(
  const EdgeAlignment & alignment, const types::DynamicObject & measurement) const
{
  // Calculate the anchor point (edge center) for wheel-based updates
  // updateStatePoseRear/Front will convert edge center to wheel position internally

  geometry_msgs::msg::Point anchor_point;

  const double meas_yaw = tf2::getYaw(measurement.pose.orientation);
  const double meas_cos_yaw = std::cos(meas_yaw);
  const double meas_sin_yaw = std::sin(meas_yaw);
  const double meas_half_length = measurement.shape.dimensions.x * 0.5;

  // Calculate the matched measurement edge center directly
  if (alignment.aligned_meas_edge == Edge::FRONT) {
    // Use measurement front edge center
    anchor_point.x = measurement.pose.position.x + meas_half_length * meas_cos_yaw;
    anchor_point.y = measurement.pose.position.y + meas_half_length * meas_sin_yaw;
  } else {
    // Use measurement rear edge center
    anchor_point.x = measurement.pose.position.x - meas_half_length * meas_cos_yaw;
    anchor_point.y = measurement.pose.position.y - meas_half_length * meas_sin_yaw;
  }

  return anchor_point;
}

bool Tracker::createPseudoMeasurement(
  const types::DynamicObject & meas, types::DynamicObject & pred,
  const autoware_perception_msgs::msg::Shape & tracker_shape, const bool enlarge_covariance)
{
  // Apply linear fall‑off weight on dist square
  const double dx = meas.pose.position.x - pred.pose.position.x;
  const double dy = meas.pose.position.y - pred.pose.position.y;
  const double dist2 = dx * dx + dy * dy;
  constexpr double d_max_square_inv = 1 / 2.0;  // saturate when distance overs 1.414 m
  constexpr double min_w = 0.0;
  const double w_pose = std::clamp(1.0 - dist2 * d_max_square_inv, min_w, 1.0);

  // Blend position
  pred.pose.position.x = pred.pose.position.x * (1 - w_pose) + meas.pose.position.x * w_pose;
  pred.pose.position.y = pred.pose.position.y * (1 - w_pose) + meas.pose.position.y * w_pose;

  // Use smoothed shape and its area
  pred.shape = tracker_shape;
  pred.area = types::getArea(tracker_shape);

  // Blend orientation
  if (meas.kinematics.orientation_availability != types::OrientationAvailability::UNAVAILABLE) {
    double yaw_pred = tf2::getYaw(pred.pose.orientation);
    double yaw_meas = tf2::getYaw(meas.pose.orientation);

    double yaw_diff = yaw_meas - yaw_pred;
    // Normalize yaw_diff to [-π, π] using fmod
    yaw_diff = std::fmod(yaw_diff + M_PI, 2 * M_PI) - M_PI;
    // Handle SIGN_UNKNOWN: limit yaw difference to [-90°, 90°]
    if (meas.kinematics.orientation_availability == types::OrientationAvailability::SIGN_UNKNOWN) {
      if (yaw_diff > M_PI_2) {
        yaw_diff -= M_PI;
      } else if (yaw_diff < -M_PI_2) {
        yaw_diff += M_PI;
      }
    }
    double yaw_fused = yaw_pred + yaw_diff * w_pose;
    tf2::Quaternion q;
    q.setRPY(0, 0, yaw_fused);
    pred.pose.orientation = tf2::toMsg(q);
  }

  // Enlarge covariance if requested (for weak updates)
  if (enlarge_covariance) {
    using autoware_utils_geometry::xyzrpy_covariance_index::XYZRPY_COV_IDX;
    constexpr double additional_position_cov = 9.0;     // [m^2] additional variance
    constexpr double additional_orientation_cov = 0.5;  // [rad^2] additional variance
    constexpr double additional_velocity_cov = 25.0;    // [m^2/s^2] additional variance

    pred.pose_covariance[XYZRPY_COV_IDX::X_X] += additional_position_cov;
    pred.pose_covariance[XYZRPY_COV_IDX::Y_Y] += additional_position_cov;
    pred.pose_covariance[XYZRPY_COV_IDX::YAW_YAW] += additional_orientation_cov;

    // Enlarge velocity covariance if available
    if (pred.kinematics.has_twist_covariance) {
      pred.twist_covariance[XYZRPY_COV_IDX::X_X] += additional_velocity_cov;
      pred.twist_covariance[XYZRPY_COV_IDX::Y_Y] += additional_velocity_cov;
    }
  }

  return true;
}

double getArea(const autoware_perception_msgs::msg::Shape & shape)
{
  switch (shape.type) {
    case autoware_perception_msgs::msg::Shape::BOUNDING_BOX:
      return shape.dimensions.x * shape.dimensions.y;
    case autoware_perception_msgs::msg::Shape::CYLINDER:
      return shape.dimensions.x * shape.dimensions.x * M_PI * 0.25;
    case autoware_perception_msgs::msg::Shape::POLYGON: {
      double area = 0.0;
      for (size_t i = 0; i < shape.footprint.points.size(); ++i) {
        size_t j = (i + 1) % shape.footprint.points.size();
        area += 0.5 * (shape.footprint.points.at(i).x * shape.footprint.points.at(j).y -
                       shape.footprint.points.at(j).x * shape.footprint.points.at(i).y);
      }
      return area;
    }
    default:
      return 0.0;
  }
}

bool VehicleTracker::measure(
  const types::DynamicObject & in_object, const rclcpp::Time & time,
  const types::InputChannel & channel_info)
{
  // check time gap
  const double dt = motion_model_.getDeltaTime(time);
  if (0.01 /*10msec*/ < dt) {
    RCLCPP_WARN(
      logger_,
      "VehicleTracker::measure There is a large gap between predicted time and measurement "
      "time. (%f)",
      dt);
  }

  // update object
  types::DynamicObject updating_object = in_object;
  // turn 180 deg if the updating object heads opposite direction
  {
    const double this_yaw = motion_model_.getYawState();
    const double updating_yaw = tf2::getYaw(updating_object.pose.orientation);
    double yaw_diff = updating_yaw - this_yaw;
    while (yaw_diff > M_PI) yaw_diff -= 2 * M_PI;
    while (yaw_diff < -M_PI) yaw_diff += 2 * M_PI;
    if (std::abs(yaw_diff) > M_PI_2) {
      tf2::Quaternion q;
      q.setRPY(0, 0, updating_yaw + M_PI);
      updating_object.pose.orientation = tf2::toMsg(q);
    }
  }

  // update pose
  measureWithPose(updating_object, channel_info);

  // remove cached object
  removeCache();

  // reset anchor point for shape updates
  shape_update_anchor_ = BicycleMotionModel::LengthUpdateAnchor::CENTER;

  return true;
}

bool VehicleTracker::measureWithPose(
  const types::DynamicObject & object, const types::InputChannel & channel_info)
{
  // get measurement yaw angle to update
  bool is_yaw_available =
    object.kinematics.orientation_availability != types::OrientationAvailability::UNAVAILABLE &&
    channel_info.trust_orientation;

  bool is_velocity_available = object.kinematics.has_twist;

  // update
  bool is_updated = false;
  {
    const double & x = object.pose.position.x;
    const double & y = object.pose.position.y;
    const double & yaw = tf2::getYaw(object.pose.orientation);
    const double & vel_x = object.twist.linear.x;
    const double & vel_y = object.twist.linear.y;
    constexpr double min_length = 1.0;  // minimum length to avoid division by zero
    const double length = std::max(object.shape.dimensions.x, min_length);

    if (is_yaw_available && is_velocity_available) {
      // update with yaw angle and velocity
      is_updated = motion_model_.updateStatePoseHeadVel(
        x, y, yaw, object.pose_covariance, vel_x, vel_y, object.twist_covariance, length);
    } else if (is_yaw_available && !is_velocity_available) {
      // update with yaw angle, but without velocity
      is_updated = motion_model_.updateStatePoseHead(x, y, yaw, object.pose_covariance, length);
    } else if (!is_yaw_available && is_velocity_available) {
      // update without yaw angle, but with velocity
      is_updated = motion_model_.updateStatePoseVel(
        x, y, object.pose_covariance, yaw, vel_x, vel_y, object.twist_covariance, length);
    } else {
      // update without yaw angle and velocity
      is_updated = motion_model_.updateStatePose(
        x, y, object.pose_covariance, length);  // update without yaw angle and velocity
    }
    motion_model_.limitStates();
  }

  // position z
  {
    constexpr double gain = 0.1;
    object_.pose.position.z =
      (1.0 - gain) * object_.pose.position.z + gain * object.pose.position.z;
  }

  if (object.shape.type != autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    // do not update shape if the input is not a bounding box
    return false;
  }

  // check object size abnormality
  constexpr double size_max_multiplier = 1.5;
  constexpr double size_min_multiplier = 0.25;
  if (
    object.shape.dimensions.x > object_model_.size_limit.length_max * size_max_multiplier ||
    object.shape.dimensions.x < object_model_.size_limit.length_min * size_min_multiplier ||
    object.shape.dimensions.y > object_model_.size_limit.width_max * size_max_multiplier ||
    object.shape.dimensions.y < object_model_.size_limit.width_min * size_min_multiplier) {
    return false;
  }

  // update object size
  {
    constexpr double gain = 0.4;
    constexpr double gain_inv = 1.0 - gain;
    auto & object_extension = object_.shape.dimensions;
    object_extension.x = motion_model_.getLength();  // tracked by motion model
    object_extension.y = gain_inv * object_extension.y + gain * object.shape.dimensions.y;
    object_extension.z = gain_inv * object_extension.z + gain * object.shape.dimensions.z;
  }

  // set maximum and minimum size
  limitObjectExtension(object_model_);

  // set shape type, which is bounding box
  object_.shape.type = autoware_perception_msgs::msg::Shape::BOUNDING_BOX;
  object_.area = types::getArea(object.shape);

  return is_updated;
}

bool BicycleMotionModel::updateStatePoseHeadVel(
  const double & x, const double & y, const double & yaw, const std::array<double, 36> & pose_cov,
  const double & vel_long, const double & vel_lat, const std::array<double, 36> & twist_cov,
  const double & length)
{
  // check if the state is initialized
  if (!checkInitialized()) return false;

  // convert the state to the bicycle model state
  const double lr = length * motion_params_.lr_ratio;
  const double lf = length * motion_params_.lf_ratio;
  const double cos_yaw = std::cos(yaw);
  const double sin_yaw = std::sin(yaw);
  const double x1 = x - lr * cos_yaw;
  const double y1 = y - lr * sin_yaw;
  const double x2 = x + lf * cos_yaw;
  const double y2 = y + lf * sin_yaw;

  // update state
  constexpr int DIM_Y = 6;
  Eigen::Matrix<double, DIM_Y, 1> Y;
  Y << x1, y1, x2, y2, vel_long, vel_lat * motion_params_.wheel_pos_ratio;

  Eigen::Matrix<double, DIM_Y, DIM> C = Eigen::Matrix<double, DIM_Y, DIM>::Zero();
  C(0, IDX::X1) = 1.0;
  C(1, IDX::Y1) = 1.0;
  C(2, IDX::X2) = 1.0;
  C(3, IDX::Y2) = 1.0;
  C(4, IDX::U) = 1.0;
  C(5, IDX::V) = 1.0;

  Eigen::Matrix<double, DIM_Y, DIM_Y> R = Eigen::Matrix<double, DIM_Y, DIM_Y>::Zero();
  R(0, 0) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(0, 1) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(1, 0) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(1, 1) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  R(2, 2) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(2, 3) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(3, 2) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(3, 3) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  R(4, 4) = twist_cov[XYZRPY_COV_IDX::X_X];
  R(5, 5) = twist_cov[XYZRPY_COV_IDX::Y_Y] * motion_params_.wheel_pos_ratio;

  return ekf_.update(Y, C, R);
}

bool update(
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> & y,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, StateSize> & C,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> & R)
{
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> y_pred = C * x_;
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> S =
    C * P_ * C.transpose() + R;
  const Eigen::Matrix<Scalar, StateSize, DynamicMeasurementSize> K =
    P_ * C.transpose() * S.inverse();

  if (!K.allFinite()) {
    return false;
  }
  x_ += K * (y - y_pred);
  P_ -= K * C * P_;
  return true;
}

inline bool DenseBase<Derived>::allFinite() const
{
#if EIGEN_COMP_MSVC || (defined __FAST_MATH__)
  return derived().array().isFinite().all();
#else
  return !((derived()-derived()).hasNaN());
#endif
}

bool BicycleMotionModel::updateStatePoseHead(
  const double & x, const double & y, const double & yaw, const std::array<double, 36> & pose_cov,
  const double & length)
{
  // check if the state is initialized
  if (!checkInitialized()) return false;

  // convert the state to the bicycle model state
  const double lr = length * motion_params_.lr_ratio;
  const double lf = length * motion_params_.lf_ratio;
  const double cos_yaw = std::cos(yaw);
  const double sin_yaw = std::sin(yaw);
  const double x1 = x - lr * cos_yaw;
  const double y1 = y - lr * sin_yaw;
  const double x2 = x + lf * cos_yaw;
  const double y2 = y + lf * sin_yaw;

  // update state
  constexpr int DIM_Y = 4;
  Eigen::Matrix<double, DIM_Y, 1> Y;
  Y << x1, y1, x2, y2;

  Eigen::Matrix<double, DIM_Y, DIM> C = Eigen::Matrix<double, DIM_Y, DIM>::Zero();
  C(0, IDX::X1) = 1.0;
  C(1, IDX::Y1) = 1.0;
  C(2, IDX::X2) = 1.0;
  C(3, IDX::Y2) = 1.0;

  Eigen::Matrix<double, DIM_Y, DIM_Y> R = Eigen::Matrix<double, DIM_Y, DIM_Y>::Zero();
  R(0, 0) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(0, 1) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(1, 0) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(1, 1) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  R(2, 2) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(2, 3) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(3, 2) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(3, 3) = pose_cov[XYZRPY_COV_IDX::Y_Y];

  return ekf_.update(Y, C, R);
}

bool update(
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> & y,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, StateSize> & C,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> & R)
{
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> y_pred = C * x_;
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> S =
    C * P_ * C.transpose() + R;
  const Eigen::Matrix<Scalar, StateSize, DynamicMeasurementSize> K =
    P_ * C.transpose() * S.inverse();

  if (!K.allFinite()) {
    return false;
  }
  x_ += K * (y - y_pred);
  P_ -= K * C * P_;
  return true;
}

bool BicycleMotionModel::updateStatePoseVel(
  const double & x, const double & y, const std::array<double, 36> & pose_cov, const double & yaw,
  const double & vel_long, const double & vel_lat, const std::array<double, 36> & twist_cov,
  const double & length)
{
  // check if the state is initialized
  if (!checkInitialized()) return false;

  // using given yaw to fix the velocity direction
  // input yaw is velocity direction
  const double ground_vel_x = vel_long * std::cos(yaw) - vel_lat * std::sin(yaw);
  const double ground_vel_y = vel_long * std::sin(yaw) + vel_lat * std::cos(yaw);
  const double vel_angle = std::atan2(ground_vel_y, ground_vel_x);
  const double vel_long_in = std::hypot(ground_vel_x, ground_vel_y);
  constexpr double vel_lat_in = 0.0;  // lateral velocity is not reliable in this case

  return updateStatePoseHeadVel(
    x, y, vel_angle, pose_cov, vel_long_in, vel_lat_in, twist_cov, length);
}

bool BicycleMotionModel::updateStatePoseHeadVel(
  const double & x, const double & y, const double & yaw, const std::array<double, 36> & pose_cov,
  const double & vel_long, const double & vel_lat, const std::array<double, 36> & twist_cov,
  const double & length)
{
  // check if the state is initialized
  if (!checkInitialized()) return false;

  // convert the state to the bicycle model state
  const double lr = length * motion_params_.lr_ratio;
  const double lf = length * motion_params_.lf_ratio;
  const double cos_yaw = std::cos(yaw);
  const double sin_yaw = std::sin(yaw);
  const double x1 = x - lr * cos_yaw;
  const double y1 = y - lr * sin_yaw;
  const double x2 = x + lf * cos_yaw;
  const double y2 = y + lf * sin_yaw;

  // update state
  constexpr int DIM_Y = 6;
  Eigen::Matrix<double, DIM_Y, 1> Y;
  Y << x1, y1, x2, y2, vel_long, vel_lat * motion_params_.wheel_pos_ratio;

  Eigen::Matrix<double, DIM_Y, DIM> C = Eigen::Matrix<double, DIM_Y, DIM>::Zero();
  C(0, IDX::X1) = 1.0;
  C(1, IDX::Y1) = 1.0;
  C(2, IDX::X2) = 1.0;
  C(3, IDX::Y2) = 1.0;
  C(4, IDX::U) = 1.0;
  C(5, IDX::V) = 1.0;

  Eigen::Matrix<double, DIM_Y, DIM_Y> R = Eigen::Matrix<double, DIM_Y, DIM_Y>::Zero();
  R(0, 0) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(0, 1) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(1, 0) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(1, 1) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  R(2, 2) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(2, 3) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(3, 2) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(3, 3) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  R(4, 4) = twist_cov[XYZRPY_COV_IDX::X_X];
  R(5, 5) = twist_cov[XYZRPY_COV_IDX::Y_Y] * motion_params_.wheel_pos_ratio;

  return ekf_.update(Y, C, R);
}

bool update(
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> & y,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, StateSize> & C,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> & R)
{
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> y_pred = C * x_;
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> S =
    C * P_ * C.transpose() + R;
  const Eigen::Matrix<Scalar, StateSize, DynamicMeasurementSize> K =
    P_ * C.transpose() * S.inverse();

  if (!K.allFinite()) {
    return false;
  }
  x_ += K * (y - y_pred);
  P_ -= K * C * P_;
  return true;
}

bool BicycleMotionModel::updateStatePose(
  const double & x, const double & y, const std::array<double, 36> & pose_cov,
  const double & length)
{
  // yaw angle is not provided, so we use the current yaw state
  const double yaw = getYawState();
  return updateStatePoseHead(x, y, yaw, pose_cov, length);
}

double BicycleMotionModel::getYawState() const
{
  // get yaw angle from the state
  return std::atan2(
    getStateElement(IDX::Y2) - getStateElement(IDX::Y1),
    getStateElement(IDX::X2) - getStateElement(IDX::X1));
}

bool BicycleMotionModel::updateStatePoseHead(
  const double & x, const double & y, const double & yaw, const std::array<double, 36> & pose_cov,
  const double & length)
{
  // check if the state is initialized
  if (!checkInitialized()) return false;

  // convert the state to the bicycle model state
  const double lr = length * motion_params_.lr_ratio;
  const double lf = length * motion_params_.lf_ratio;
  const double cos_yaw = std::cos(yaw);
  const double sin_yaw = std::sin(yaw);
  const double x1 = x - lr * cos_yaw;
  const double y1 = y - lr * sin_yaw;
  const double x2 = x + lf * cos_yaw;
  const double y2 = y + lf * sin_yaw;

  // update state
  constexpr int DIM_Y = 4;
  Eigen::Matrix<double, DIM_Y, 1> Y;
  Y << x1, y1, x2, y2;

  Eigen::Matrix<double, DIM_Y, DIM> C = Eigen::Matrix<double, DIM_Y, DIM>::Zero();
  C(0, IDX::X1) = 1.0;
  C(1, IDX::Y1) = 1.0;
  C(2, IDX::X2) = 1.0;
  C(3, IDX::Y2) = 1.0;

  Eigen::Matrix<double, DIM_Y, DIM_Y> R = Eigen::Matrix<double, DIM_Y, DIM_Y>::Zero();
  R(0, 0) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(0, 1) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(1, 0) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(1, 1) = pose_cov[XYZRPY_COV_IDX::Y_Y];
  R(2, 2) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(2, 3) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(3, 2) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(3, 3) = pose_cov[XYZRPY_COV_IDX::Y_Y];

  return ekf_.update(Y, C, R);
}

bool update(
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> & y,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, StateSize> & C,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> & R)
{
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> y_pred = C * x_;
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> S =
    C * P_ * C.transpose() + R;
  const Eigen::Matrix<Scalar, StateSize, DynamicMeasurementSize> K =
    P_ * C.transpose() * S.inverse();

  if (!K.allFinite()) {
    return false;
  }
  x_ += K * (y - y_pred);
  P_ -= K * C * P_;
  return true;
}

bool BicycleMotionModel::limitStates()
{
  StateVec X_t;
  StateMat P_t;
  ekf_.getX(X_t);
  ekf_.getP(P_t);

  // maximum reverse velocity
  if (motion_params_.max_reverse_vel < 0 && X_t(IDX::U) < motion_params_.max_reverse_vel) {
    // rotate the object orientation by 180 degrees
    // replace X1 and Y1 with X2 and Y2
    const double x_center =
      (X_t(IDX::X1) * motion_params_.lf_ratio + X_t(IDX::X2) * motion_params_.lr_ratio) *
      motion_params_.wheel_base_ratio_inv;
    const double y_center =
      (X_t(IDX::Y1) * motion_params_.lf_ratio + X_t(IDX::Y2) * motion_params_.lr_ratio) *
      motion_params_.wheel_base_ratio_inv;
    const double x1_rel = X_t(IDX::X1) - x_center;
    const double y1_rel = X_t(IDX::Y1) - y_center;
    const double x2_rel = X_t(IDX::X2) - x_center;
    const double y2_rel = X_t(IDX::Y2) - y_center;

    X_t(IDX::X1) = x_center + x2_rel;
    X_t(IDX::Y1) = y_center + y2_rel;
    X_t(IDX::X2) = x_center + x1_rel;
    X_t(IDX::Y2) = y_center + y1_rel;

    // reverse the velocity
    X_t(IDX::U) = -X_t(IDX::U);
    // rotation velocity does not change

    // replace covariance
    // Swap rows and columns
    P_t.row(IDX::X1).swap(P_t.row(IDX::X2));
    P_t.row(IDX::Y1).swap(P_t.row(IDX::Y2));
    P_t.col(IDX::X1).swap(P_t.col(IDX::X2));
    P_t.col(IDX::Y1).swap(P_t.col(IDX::Y2));
  }
  // maximum velocity
  if (!(-motion_params_.max_vel <= X_t(IDX::U) && X_t(IDX::U) <= motion_params_.max_vel)) {
    X_t(IDX::U) = X_t(IDX::U) < 0 ? -motion_params_.max_vel : motion_params_.max_vel;
  }

  // maximum lateral velocity by lateral acceleration limitations
  // a_max = vel_long^2 * vel_lat / wheel_base
  // vel_lat_limit = a_max * wheel_base / vel_long^2
  {
    const double wheel_base = std::hypot(X_t(IDX::X2) - X_t(IDX::X1), X_t(IDX::Y2) - X_t(IDX::Y1));
    constexpr double acc_lat_max = 9.81 * 0.5;  // [m/s^2] maximum lateral acceleration (0.5g);
    const double vel_lat_limit = acc_lat_max * wheel_base / (X_t(IDX::U) * X_t(IDX::U));
    const double vel_lat_limit_adjusted = vel_lat_limit * motion_params_.wheel_pos_ratio;
    if (std::abs(X_t(IDX::V)) > vel_lat_limit_adjusted) {
      // limit lateral velocity
      X_t(IDX::V) = X_t(IDX::V) < 0 ? -vel_lat_limit_adjusted : vel_lat_limit_adjusted;
    }
  }

  // overwrite state
  ekf_.init(X_t, P_t);
  return true;
}

void removeCache() const
{
  cached_time_ = rclcpp::Time();
  cached_object_ = types::DynamicObject();
  cached_measurement_count_ = -1;
}

bool BicycleMotionModel::updateStatePoseFront(
  const double & xf, const double & yf, const std::array<double, 36> & pose_cov)
{
  // check if the state is initialized
  if (!checkInitialized()) return false;

  // get the current state to extract renovate deviation
  StateVec X_t;
  StateMat P_t;
  ekf_.getX(X_t);
  ekf_.getP(P_t);

  const double yaw = getYawState();
  const double wheel_base = std::hypot(X_t(IDX::X2) - X_t(IDX::X1), X_t(IDX::Y2) - X_t(IDX::Y1));
  const double x2 = xf - wheel_base * motion_params_.wheel_gamma_front * std::cos(yaw);
  const double y2 = yf - wheel_base * motion_params_.wheel_gamma_front * std::sin(yaw);
  const double delta_x = x2 - X_t(IDX::X2);
  const double delta_y = y2 - X_t(IDX::Y2);

  // update state
  constexpr int DIM_Y = 4;
  Eigen::Matrix<double, DIM_Y, 1> Y;
  Y << X_t(IDX::X1) + delta_x, X_t(IDX::Y1) + delta_y, x2, y2;

  Eigen::Matrix<double, DIM_Y, DIM> C = Eigen::Matrix<double, DIM_Y, DIM>::Zero();
  C(0, IDX::X1) = 1.0;
  C(1, IDX::Y1) = 1.0;
  C(2, IDX::X2) = 1.0;
  C(3, IDX::Y2) = 1.0;

  constexpr double uncertainty_multiplier = 9.0;  // additional uncertainty for unmeasured position
  Eigen::Matrix<double, DIM_Y, DIM_Y> R = Eigen::Matrix<double, DIM_Y, DIM_Y>::Zero();
  R(0, 0) = pose_cov[XYZRPY_COV_IDX::X_X] * uncertainty_multiplier;
  R(0, 1) = pose_cov[XYZRPY_COV_IDX::X_Y] * uncertainty_multiplier;
  R(1, 0) = pose_cov[XYZRPY_COV_IDX::Y_X] * uncertainty_multiplier;
  R(1, 1) = pose_cov[XYZRPY_COV_IDX::Y_Y] * uncertainty_multiplier;
  R(2, 2) = pose_cov[XYZRPY_COV_IDX::X_X];
  R(2, 3) = pose_cov[XYZRPY_COV_IDX::X_Y];
  R(3, 2) = pose_cov[XYZRPY_COV_IDX::Y_X];
  R(3, 3) = pose_cov[XYZRPY_COV_IDX::Y_Y];

  return ekf_.update(Y, C, R);
}

double BicycleMotionModel::getYawState() const
{
  // get yaw angle from the state
  return std::atan2(
    getStateElement(IDX::Y2) - getStateElement(IDX::Y1),
    getStateElement(IDX::X2) - getStateElement(IDX::X1));
}

bool update(
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> & y,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, StateSize> & C,
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> & R)
{
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, 1> y_pred = C * x_;
  const Eigen::Matrix<Scalar, DynamicMeasurementSize, DynamicMeasurementSize> S =
    C * P_ * C.transpose() + R;
  const Eigen::Matrix<Scalar, StateSize, DynamicMeasurementSize> K =
    P_ * C.transpose() * S.inverse();

  if (!K.allFinite()) {
    return false;
  }
  x_ += K * (y - y_pred);
  P_ -= K * C * P_;
  return true;
}
